mapper.sql:
SELECT M1.ID, M1.MAC_CODE, M1.MAC_NAME, M1.MAC_TYPE_CODE, M2.MAC_TYPE_NAME, M1.MAC_MODEL_CODE, M3.MODEL_NAME MAC_MODEL_NAME, M1.DEPT_ID, SD.DEPT_NAME, M1.IMEI, M1.STATUS, M1.IS_ELECTRON_FENCE, M1.CREATE_BY, M1.CREATE_TIME, M1.UPDATE_BY, M1.UPDATE_TIME FROM M_MACHINE M1 JOIN M_MACHINE_TYPE M2 ON M1.MAC_TYPE_CODE = M2.MAC_TYPE_CODE LEFT JOIN M_MACHINE_TYPE_MODEL M3 ON M1.MAC_MODEL_CODE = M3.MODEL_CODE LEFT JOIN SYS_DEPT SD ON SD.ID = M1.DEPT_ID
and M1.MAC_CODE LIKE #{macCode}
and M1.MAC_NAME LIKE #{macName}
and M1.MAC_TYPE_CODE = #{macTypeCode}
and M1.DEPT_ID = #{deptId}
and M1.STATUS = #{status}
and M1.IS_ELECTRON_FENCE = #{isElectronFence}

mapper.select:
select count(*)
from T_YARD_TALLY TYT
where TYT.EQUIPMENT_ID  = #{id}
